class Solution:
    def goodIndices(self, nums, k):
        n = len(nums)
        res = []
        for i in range(k, n - k):
            ok = True
            for j in range(i - k, i - 1):
                if nums[j] < nums[j + 1]:
                    ok = False
                    break
            if ok:
                for j in range(i + 1, i + k):
                    if nums[j] > nums[j + 1]:
                        ok = False
                        break
            if ok:
                res.append(i)
        return res

